import { task, batch } from "@trigger.dev/sdk";

export const processItem = task({
  id: "process-item-${trial_id}",
  run: async (payload: { id: string }) => {
    return payload.id;
  },
});

export const batchProcessor = task({
  id: "batch-processor-${trial_id}",
  run: async (payload: { ids: string[] }) => {
    const payloads = payload.ids.map((id) => ({ id }));
    const results = await batch.triggerByTaskAndWait(processItem, { payloads });

    return results;
  },
});

